import Cart from "./components/Cart/Cart";
import Layout from "./components/Layout/Layout";
import Products from "./components/Shop/Products";
import { useSelector, useDispatch } from "react-redux";
import { useEffect, Fragment } from "react";
import { uiActions } from "./store/ui-slice";
import Notification from "./components/UI/Notification";

function App() {
  const showCart = useSelector((state) => state.ui.cartIsVisible);
  const cart = useSelector((state) => state.cart);
  const dispatch = useDispatch();
  const notification = useSelector((state) => state.ui.notification);

  useEffect(() => {
    const sendCardData = async () => {
      dispatch(
        uiActions.showNtification({
          status: "pending",
          title: "sending...",
          message: "sending cart data",
        }),
      );

      const response = await fetch(
        "https://react-section-21-ab48a-default-rtdb.europe-west1.firebasedatabase.app/cart.json",
        {
          method: "PUT",
          body: JSON.stringify(cart),
        },
      );

      if (!response.ok) {
        throw new Error("sending cart data failed");
      }

      dispatch(
        uiActions.showNtification({
          status: "success",
          title: "success...",
          message: "sent cart data successfully",
        }),
      );

      sendCardData().catch((error) => {
        dispatch(
          uiActions.showNtification({
            status: "error",
            title: "error...",
            message: "sending cart data failed",
          }),
        );
      });
    };
  }, [cart, dispatch]);

  return (
    <Fragment>
      {notification && (
        <Notification
          status={notification.status}
          title={notification.title}
          message={notification.message}
        />
      )}
      <Layout>
        {showCart && <Cart />}
        <Products />
      </Layout>
    </Fragment>
  );
}

export default App;

/*
NOTES: 
- reducers must me pure, side-effect free, synchronous functions
- side-effects & async tasks can go: in the components (useEffect()) or
inside custom action creators
*/
